#include <iostream>\n#include <vector>\n#include <limits>\n\nclass Graph {\n public:\n  explicit Graph(const std::vector<std::vector<int>>& matrix) : matrix_(matrix) {\n    n_ = static_cast<int>(matrix_.size());\n    dists_.resize(n_, std::vector<int>(n_, kInf));\n    Build();\n  }\n\n  const std::vector<std::vector<int>>& GetDist() {\n    return dists_;\n  }\n\n private:\n  void Build() {\n    dists_ = matrix_;\n    for (int i = 0; i < n_; i++) {\n      for (int u = 0; u < n_; u++) {\n        for (int v = 0; v < n_; v++) {\n          dists_[u][v] = std::min(dists_[u][v], dists_[u][i] + dists_[i][v]);\n        }\n      }\n    }\n  }\n\n  int n_;\n  static constexpr int kInf = std::numeric_limits<int>::max();\n  std::vector<std::vector<int>> matrix_;\n  std::vector<std::vector<int>> dists_;\n};\n\nint main() {\n  int n = 0;\n  std::cin >> n;\n  std::vector<std::vector<int>> matrix(n, std::vector<int>(n));\n  for (int i = 0; i < n; i++) {\n    for (int j = 0; j < n; j++) {\n      std::cin >> matrix[i][j];\n    }\n  }\n\n  Graph g(matrix);\n\n  for (const std::vector<int>& row : g.GetDist()) {\n    for (int i : row) {\n      std::cout << i << ' ';\n    }\n    std::cout << std::endl;\n  }\n\n  return 0;\n}